WITH payload AS (
  SELECT $RISQQ101${"questions":[{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.10","internal_question_no":"08D.010","question_sort_key":8401000.298,"question_text":"Is an approved ship specific Cargo Securing Manual available, and are officers thoroughly familiar with the contents of the manual and is the lashing plan compatible with the design of the vessel?","guide_to_inspection":"Record a Finding if the vessel has deviated from the approved lashing arrangements shown in the Cargo Securing Manual,\nexcept to add additional lashings.\nIn accordance with the SOLAS chapters VI, VII and the Code of Safe Practice for Cargo Stowage and Securing (CSS Code), cargo\nunits, including containers shall be stowed and secured throughout the voyage in accordance with a Cargo Securing Manual\n(CSM), approved by the Administration.\nThe CSM should be developed, considering the recommendations given in these Guidelines and should be written in the working\nlanguage or languages of the ship. If one of the working languages is not English, French, or Spanish, a translation into one of\nthese languages should be included.\n> The guidance given in the CSM should by no means rule out the principles of good seamanship, neither can it replace\nexperience in stowage and securing practice.\n> The information and requirements set forth in the manual should be consistent with the requirements of the vessel’s trim\nand stability booklet, International Load Line Certificate (1966), the hull strength loading manual (if provided) and with the\nrequirements of the International Maritime Dangerous Goods (IMDG) Code (if applicable).\n> The CSM should specify arrangements and cargo-securing devices provided on board the ship for the correct application\nto and the securing of cargo units, containers, vehicles, and other entities, based on transverse, longitudinal and vertical\nforces which may arise during adverse weather and sea conditions.\n> It is imperative to the safety of the ship and the protection of the cargo and personnel that the securing of the cargo is\ncarried out properly and that only appropriate securing points or fittings should be used for securing cargo.\n> The cargo-securing devices mentioned in the manual should be suitable and adapted to the quantity, type of packaging,\nand physical properties of the cargo to be carried. When new or alternative types of cargo-securing devices are introduced,\nthe manual should be revised accordingly. Alternative cargo- securing devices introduced should not have less strength\nthan the devices being replaced.\n> There should be a sufficient quantity of reserve cargo-securing devices on board the ship.\n> Information on the strength and instructions for the use and maintenance of each specific type of cargo-securing device,\nwhere applicable, should be provided in the manual. The cargo- securing devices should be maintained in a satisfactory\ncondition. Items worn or damaged to such an extent that their quality is impaired should be replaced.\n> The Cargo Safe Access Plan (CSAP) is intended to provide detailed information for persons engaged in work connected\nwith cargo stowage and securing. Safe access should be provided and maintained in accordance with this plan.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nNote: The Cargo Safe Access Plan (CSAP) is only required for containerships with keel-laying date on or after 1 January 2015.\n> The Cargo Securing Manual should be updated as appropriate. Whenever the ship’s outfit of portable cargo securing\ndevices changes, those changes should be recorded in the appropriate section of the CSM. An appropriate record should\nbe completed whenever routine visual examinations or periodic detailed examinations and re-testing of the devices are\ncarried out.\n(Bliault and North of England, P & I Association, 2007)\n> Lashing plans contained within the approved Cargo Securing Manual should be compatible with the current design of the\nship and the intended container securing method must be both safe and physically possible. The CSM, lashing plans and\nthe CSAP must be kept up to date.\n> Lashing plans and the CSAP are compatible with the design of the vessel and the equipment available.\n(CSS code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":151,"source_page_end":152,"raw_source_text":"Is an approved ship specific Cargo Securing Manual available, and are officers thoroughly familiar\nwith the contents of the manual and is the lashing plan compatible with the design of the vessel? (V)\nGuide to Inspection\nRecord a Finding if the vessel has deviated from the approved lashing arrangements shown in the Cargo Securing Manual,\nexcept to add additional lashings.\nIn accordance with the SOLAS chapters VI, VII and the Code of Safe Practice for Cargo Stowage and Securing (CSS Code), cargo\nunits, including containers shall be stowed and secured throughout the voyage in accordance with a Cargo Securing Manual\n(CSM), approved by the Administration.\nThe CSM should be developed, considering the recommendations given in these Guidelines and should be written in the working\nlanguage or languages of the ship. If one of the working languages is not English, French, or Spanish, a translation into one of\nthese languages should be included.\n> The guidance given in the CSM should by no means rule out the principles of good seamanship, neither can it replace\nexperience in stowage and securing practice.\n> The information and requirements set forth in the manual should be consistent with the requirements of the vessel’s trim\nand stability booklet, International Load Line Certificate (1966), the hull strength loading manual (if provided) and with the\nrequirements of the International Maritime Dangerous Goods (IMDG) Code (if applicable).\n> The CSM should specify arrangements and cargo-securing devices provided on board the ship for the correct application\nto and the securing of cargo units, containers, vehicles, and other entities, based on transverse, longitudinal and vertical\nforces which may arise during adverse weather and sea conditions.\n> It is imperative to the safety of the ship and the protection of the cargo and personnel that the securing of the cargo is\ncarried out properly and that only appropriate securing points or fittings should be used for securing cargo.\n> The cargo-securing devices mentioned in the manual should be suitable and adapted to the quantity, type of packaging,\nand physical properties of the cargo to be carried. When new or alternative types of cargo-securing devices are introduced,\nthe manual should be revised accordingly. Alternative cargo- securing devices introduced should not have less strength\nthan the devices being replaced.\n> There should be a sufficient quantity of reserve cargo-securing devices on board the ship.\n> Information on the strength and instructions for the use and maintenance of each specific type of cargo-securing device,\nwhere applicable, should be provided in the manual. The cargo- securing devices should be maintained in a satisfactory\ncondition. Items worn or damaged to such an extent that their quality is impaired should be replaced.\n> The Cargo Safe Access Plan (CSAP) is intended to provide detailed information for persons engaged in work connected\nwith cargo stowage and securing. Safe access should be provided and maintained in accordance with this plan.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nNote: The Cargo Safe Access Plan (CSAP) is only required for containerships with keel-laying date on or after 1 January 2015.\n> The Cargo Securing Manual should be updated as appropriate. Whenever the ship’s outfit of portable cargo securing\ndevices changes, those changes should be recorded in the appropriate section of the CSM. An appropriate record should\nbe completed whenever routine visual examinations or periodic detailed examinations and re-testing of the devices are\ncarried out.\n(Bliault and North of England, P & I Association, 2007)\n> Lashing plans contained within the approved Cargo Securing Manual should be compatible with the current design of the\nship and the intended container securing method must be both safe and physically possible. The CSM, lashing plans and\nthe CSAP must be kept up to date.\n> Lashing plans and the CSAP are compatible with the design of the vessel and the equipment available.\n(CSS code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.11","internal_question_no":"08D.011","question_sort_key":8401100.299,"question_text":"Are records maintained of the regular inspection and maintenance of the cargo-securing devices on board the ship?","guide_to_inspection":"Equipment considered to be in poor condition is to be marked and not used. All relevant actions for replacement of such equipment\nare to be taken. The equipment in use should be in good condition, inspected as appropriate in accordance with Class and/or\nmaker’s guidance.\nIt is important that each device used for securing cargo should be marked clearly with its SWL and a batch mark or number, where\nthat mark can be verified by a test certificate. RightShip recommends that these test certificates be clearly labelled and kept in an\neasily accessible file. A method of correct identification and matching of individual certificates with the cargo-securing devices\nshould be established on board. Cargo-securing devices without certificates must not be used on board.\nPortable fittings should be certified by some form of type-approved system, usually coming from manufacturer (when approved), a\nClassification Society or other accepted testing body.\nThe inspection and maintenance schemes of the cargo-securing devices on board the ship shall be carried out as specified in the\nCargo Securing Manual. Regular inspections and maintenance should be carried out under the responsibility of the Master.\nInspection of cargo-securing devices should include as a minimum:\n> Routine visual examinations of components being utilised; and\n> Periodic examinations/re-testing as required by the Administration. When required, the cargo-securing devices concerned\nshould be subjected to inspections by the Administration.\n>\nInspection and maintenance of the ship’s cargo-securing devices should be documented. Entries should be made in a record book,\nwhich should be kept with the Cargo Securing Manual. This record book should contain the following information:\n> Procedures for accepting, maintaining, and repairing or rejecting cargo-securing devices; and\n> Record of inspections.\nThe record should contain information for the Master regarding inspections and adjustment of securing arrangements during the\nvoyage.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nThe cell guides, loose lashing and securing equipment including twist locks should be in good condition and free of excessive\nwear and corrosion. Twist locks, lashing and securing equipment of the same type and number as specified in the approved Cargo\nSecuring Manual should be available on board.\nTwist locks can be rated for different tensile loads up to 20 or 25 tonnes. It is important not to use a mix of twist locks that have\ndifferent strength ratings.\n(A Master’s Guide to: Container Securing, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":152,"source_page_end":153,"raw_source_text":"Are records maintained of the regular inspection and maintenance of the cargo-securing devices\non board the ship? (V)\nGuide to Inspection\nEquipment considered to be in poor condition is to be marked and not used. All relevant actions for replacement of such equipment\nare to be taken. The equipment in use should be in good condition, inspected as appropriate in accordance with Class and/or\nmaker’s guidance.\nIt is important that each device used for securing cargo should be marked clearly with its SWL and a batch mark or number, where\nthat mark can be verified by a test certificate. RightShip recommends that these test certificates be clearly labelled and kept in an\neasily accessible file. A method of correct identification and matching of individual certificates with the cargo-securing devices\nshould be established on board. Cargo-securing devices without certificates must not be used on board.\nPortable fittings should be certified by some form of type-approved system, usually coming from manufacturer (when approved), a\nClassification Society or other accepted testing body.\nThe inspection and maintenance schemes of the cargo-securing devices on board the ship shall be carried out as specified in the\nCargo Securing Manual. Regular inspections and maintenance should be carried out under the responsibility of the Master.\nInspection of cargo-securing devices should include as a minimum:\n> Routine visual examinations of components being utilised; and\n> Periodic examinations/re-testing as required by the Administration. When required, the cargo-securing devices concerned\nshould be subjected to inspections by the Administration.\n>\nInspection and maintenance of the ship’s cargo-securing devices should be documented. Entries should be made in a record book,\nwhich should be kept with the Cargo Securing Manual. This record book should contain the following information:\n> Procedures for accepting, maintaining, and repairing or rejecting cargo-securing devices; and\n> Record of inspections.\nThe record should contain information for the Master regarding inspections and adjustment of securing arrangements during the\nvoyage.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nThe cell guides, loose lashing and securing equipment including twist locks should be in good condition and free of excessive\nwear and corrosion. Twist locks, lashing and securing equipment of the same type and number as specified in the approved Cargo\nSecuring Manual should be available on board.\nTwist locks can be rated for different tensile loads up to 20 or 25 tonnes. It is important not to use a mix of twist locks that have\ndifferent strength ratings.\n(A Master’s Guide to: Container Securing, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.12","internal_question_no":"08D.012","question_sort_key":8401200.3,"question_text":"Is there a sufficient quantity of reserve cargo- securing devices on board?","guide_to_inspection":"There should be a sufficient quantity of reserve cargo-securing devices on board to deal with unexpected circumstances as per\nthe Cargo Securing Manual.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":153,"source_page_end":153,"raw_source_text":"Is there a sufficient quantity of reserve cargo- securing devices on board? (V)\nGuide to Inspection\nThere should be a sufficient quantity of reserve cargo-securing devices on board to deal with unexpected circumstances as per\nthe Cargo Securing Manual.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.13","internal_question_no":"08D.013","question_sort_key":8401300.301,"question_text":"Is the Cargo Safe Access Plan (CSAP) prepared and was it followed on board?","guide_to_inspection":"Applicable to ships with keel laid on or after 01 January 2015.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":153,"source_page_end":153,"raw_source_text":"Is the Cargo Safe Access Plan (CSAP) prepared and was it followed on board? (V)\nGuide to Inspection\nApplicable to ships with keel laid on or after 01 January 2015.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.14","internal_question_no":"08D.014","question_sort_key":8401400.302,"question_text":"Are appropriate securing points being used for cargo securing and is there recorded evidence of regular inspection and maintenance of them?","guide_to_inspection":"Deck securing points must provide effective leads in terms of the axes of the forces being resisted and be so arranged to avoid\nchafing. The securing points must not be overloaded by holding more lashings than they can safely take, and, if necessary\nadditional points are to be welded. Securing points on deck to be marked as appropriate. Safe Working load to be measured\nas per Class instructions. Maintenance to be conducted as required. Regular inspection of fixed deck fittings is essential to\nestablish whether progressive wear has undermined their integrity.\n(Container carriage- A selection of articles previously published by Gard AS, 2014)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":153,"source_page_end":153,"raw_source_text":"Are appropriate securing points being used for cargo securing and is there recorded evidence of\nregular inspection and maintenance of them? (V)\nGuide to Inspection\nDeck securing points must provide effective leads in terms of the axes of the forces being resisted and be so arranged to avoid\nchafing. The securing points must not be overloaded by holding more lashings than they can safely take, and, if necessary\nadditional points are to be welded. Securing points on deck to be marked as appropriate. Safe Working load to be measured\nas per Class instructions. Maintenance to be conducted as required. Regular inspection of fixed deck fittings is essential to\nestablish whether progressive wear has undermined their integrity.\n(Container carriage- A selection of articles previously published by Gard AS, 2014)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.15","internal_question_no":"08D.015","question_sort_key":8401500.303,"question_text":"Are there procedures for reporting and removal of damaged lashing devices from service and are there records to demonstrate that damaged lashing devices have been removed from service?","guide_to_inspection":"A container ship Master must be prepared to use all available tools in the ISM system in order to report defective stowage to the\nvessel operators and designated person ashore. It is a fundamental requirement of ISM that defects of this type are reported.\n(Container lashing and stowage, 2004)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":153,"source_page_end":153,"raw_source_text":"Are there procedures for reporting and removal of damaged lashing devices from service and are\nthere records to demonstrate that damaged lashing devices have been removed from service? (V)\nGuide to Inspection\nA container ship Master must be prepared to use all available tools in the ISM system in order to report defective stowage to the\nvessel operators and designated person ashore. It is a fundamental requirement of ISM that defects of this type are reported.\n(Container lashing and stowage, 2004)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.16","internal_question_no":"08D.016","question_sort_key":8401600.304,"question_text":"Is a Class-approved loading computer or programme in use and has its operational accuracy been regularly tested?","guide_to_inspection":"Record a Finding if the class approved container stowage calculations for lashing, stack weight and visibility were not\nincorporated in the shipboard loading computer or program.\nA stability instrument installed on board should cover all stability requirements applicable to the ship. The software is subject\nto approval by the Administration. An operation manual should be provided for the stability instrument. The language in which\nthe stability calculation results are displayed and printed out as well as the operation manual is written should be the same as\nused in the ship’s approved stability booklet. A translation into a language considered appropriate may be required. In case of\nmodifications of the ship which cause alterations in the stability booklet, the specific approval of any original stability calculation\nsoftware is no longer valid. The software should be modified accordingly and re-approved. Any change in software version\nrelated to the stability calculation should be reported to and be approved by the Administration.\nIt is the responsibility of the ship’s Master to check the accuracy of the stability instrument at each annual survey by applying at\nleast one approved test condition. If an Administration’s representative is not present for the stability instrument check, a copy\nof the test condition results obtained by this check should be retained on board as documentation of satisfactory testing for\nverification by the Administration’s representative. At each renewal survey this checking for all approved test loading conditions\nshould be done in the presence of the Administration’s representative.\n(Resolution MSC.267 (85), Adoption of the International Code on Intact Stability, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":154,"source_page_end":154,"raw_source_text":"Is a Class-approved loading computer or programme in use and has its operational accuracy been\nregularly tested? (V)\nGuide to Inspection\nRecord a Finding if the class approved container stowage calculations for lashing, stack weight and visibility were not\nincorporated in the shipboard loading computer or program.\nA stability instrument installed on board should cover all stability requirements applicable to the ship. The software is subject\nto approval by the Administration. An operation manual should be provided for the stability instrument. The language in which\nthe stability calculation results are displayed and printed out as well as the operation manual is written should be the same as\nused in the ship’s approved stability booklet. A translation into a language considered appropriate may be required. In case of\nmodifications of the ship which cause alterations in the stability booklet, the specific approval of any original stability calculation\nsoftware is no longer valid. The software should be modified accordingly and re-approved. Any change in software version\nrelated to the stability calculation should be reported to and be approved by the Administration.\nIt is the responsibility of the ship’s Master to check the accuracy of the stability instrument at each annual survey by applying at\nleast one approved test condition. If an Administration’s representative is not present for the stability instrument check, a copy\nof the test condition results obtained by this check should be retained on board as documentation of satisfactory testing for\nverification by the Administration’s representative. At each renewal survey this checking for all approved test loading conditions\nshould be done in the presence of the Administration’s representative.\n(Resolution MSC.267 (85), Adoption of the International Code on Intact Stability, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.17","internal_question_no":"08D.017","question_sort_key":8401700.305,"question_text":"Was the pre-loading plan forwarded to the ship prior to loading and is there evidence to show that the ship’s loading plan was updated and reviewed by the Chief Officer prior to loading?","guide_to_inspection":"The pre-loading plan received from the terminal planner should be entered into the shipboard loading computer. The draft\nballast plan should also be entered, and an initial evaluation of the ship’s condition should be performed and consequential\ncorrective action identified.\nStack weight limitations and lashing limitations should be identified. Any corrective actions or changes that need to be taken to\nensure compliance should be discussed with the terminal planner and stowage co-ordinator as required.\nBridge visibility rules in accordance with SOLAS must be observed and checked.\n(Safe Transport of Containers by Sea-Guidelines on Best Practices, 2008)\nShips’ staff should not allow loading operations to commence until they have received a copy of the proposed stowage plan.\nIt may be the case that a full stowage plan has not been completed, but a loading terminal should be able to give the plan for\nthe bays about to be worked. A relatively quick inspection should show whether heavy containers have been planned over light\nones; and whether the stack and tier weights are within the permissible limits.\nA reason for this is that the system for container loading is entirely driven from ashore by the planner, who creates a stowage\nplan and has the ability to vary and modify it right up to the moment a particular unit is picked up by a crane. It is frequently the\ncase that the final bay plan, received after work has been completed, bears only passing resemblance to the pre-load plan which\nwas received just as work was commencing.\n(UK P&I CLUB, Carefully to Carry Consolidated Edition, 2018)\nIn November 2014, the IMO Maritime Safety Committee adopted an amendment to SOLAS to require that shippers obtain the\n‘verified gross mass’ (VGM) of packed containers and communicate it to the ocean carrier sufficiently in advance of the ship’s\nstowage planning. Ocean carriers are obliged to use the VGM in the stowage plan and, together with the terminal operator, ensure\nthat any container that does not have a VGM is not loaded on a ship. The revised regulation entered into effect on 1 July 2016.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":154,"source_page_end":154,"raw_source_text":"Was the pre-loading plan forwarded to the ship prior to loading and is there evidence to show that\nthe ship’s loading plan was updated and reviewed by the Chief Officer prior to loading? (V)\nGuide to Inspection\nThe pre-loading plan received from the terminal planner should be entered into the shipboard loading computer. The draft\nballast plan should also be entered, and an initial evaluation of the ship’s condition should be performed and consequential\ncorrective action identified.\nStack weight limitations and lashing limitations should be identified. Any corrective actions or changes that need to be taken to\nensure compliance should be discussed with the terminal planner and stowage co-ordinator as required.\nBridge visibility rules in accordance with SOLAS must be observed and checked.\n(Safe Transport of Containers by Sea-Guidelines on Best Practices, 2008)\nShips’ staff should not allow loading operations to commence until they have received a copy of the proposed stowage plan.\nIt may be the case that a full stowage plan has not been completed, but a loading terminal should be able to give the plan for\nthe bays about to be worked. A relatively quick inspection should show whether heavy containers have been planned over light\nones; and whether the stack and tier weights are within the permissible limits.\nA reason for this is that the system for container loading is entirely driven from ashore by the planner, who creates a stowage\nplan and has the ability to vary and modify it right up to the moment a particular unit is picked up by a crane. It is frequently the\ncase that the final bay plan, received after work has been completed, bears only passing resemblance to the pre-load plan which\nwas received just as work was commencing.\n(UK P&I CLUB, Carefully to Carry Consolidated Edition, 2018)\nIn November 2014, the IMO Maritime Safety Committee adopted an amendment to SOLAS to require that shippers obtain the\n‘verified gross mass’ (VGM) of packed containers and communicate it to the ocean carrier sufficiently in advance of the ship’s\nstowage planning. Ocean carriers are obliged to use the VGM in the stowage plan and, together with the terminal operator, ensure\nthat any container that does not have a VGM is not loaded on a ship. The revised regulation entered into effect on 1 July 2016.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.18","internal_question_no":"08D.018","question_sort_key":8401800.306,"question_text":"Is there recorded evidence to show that the pre-loading plan has been checked for ‘heavy’ container stacks?","guide_to_inspection":"Container stacks are containers which are stacked vertically and secured horizontally by stackers, lashing etc. Prior to loading\ncargo, stacking weights of containers must be checked against the allowable stack weights on board the vessel, both on deck\nand under deck. Neglecting this procedure may cause serious damage to the ship’s structure, hull and eventually overall stability\nof the ship may be affected. Maximum allowable stack weights of tank tops, hatch covers, and decks shall not be exceeded at\nany time.\nShips’ staff should always check the pre-loading plan for ‘heavy’ container stacks. These should be identified and, if possible,\nthe container numbers in these stacks checked during loading. If a different container appears in the upper tier then it may be a\nheavy unit stowed by mistake and of sufficient weight to overload the stack and the lashing system.\n(UK P&I CLUB, Carefully to Carry Consolidated Edition, 2018)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":155,"source_page_end":155,"raw_source_text":"Is there recorded evidence to show that the pre-loading plan has been checked for ‘heavy’\ncontainer stacks? (V)\nGuide to Inspection\nContainer stacks are containers which are stacked vertically and secured horizontally by stackers, lashing etc. Prior to loading\ncargo, stacking weights of containers must be checked against the allowable stack weights on board the vessel, both on deck\nand under deck. Neglecting this procedure may cause serious damage to the ship’s structure, hull and eventually overall stability\nof the ship may be affected. Maximum allowable stack weights of tank tops, hatch covers, and decks shall not be exceeded at\nany time.\nShips’ staff should always check the pre-loading plan for ‘heavy’ container stacks. These should be identified and, if possible,\nthe container numbers in these stacks checked during loading. If a different container appears in the upper tier then it may be a\nheavy unit stowed by mistake and of sufficient weight to overload the stack and the lashing system.\n(UK P&I CLUB, Carefully to Carry Consolidated Edition, 2018)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.19","internal_question_no":"08D.019","question_sort_key":8401900.307,"question_text":"Has the vessel avoided loading of heavy containers above light containers or at the top of a stack in a deck stow?","guide_to_inspection":"Heavy on light can only be accepted when specifically permitted in the Cargo Securing Manual.\nIt is essential to avoid loading heavy containers over light, or at the top of a stack in a deck stow, unless specifically permitted in\nthe Cargo Securing Manual. This is because the securing system would normally have been designed on the assumption that\nlight containers are stowed on top. Stowage may allow for ‘heavy-heavy-light’; however, loading ‘heavy-medium-medium’ may\nresult in the same stack weight but would produce different strain on the securing system, especially if the GM is high.\n(A Master Guide to: Container Securing, 2012)\nLoading heavy containers top stow may cause stability problem and excessive lashing strains during ship’s motions at sea.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":155,"source_page_end":155,"raw_source_text":"Has the vessel avoided loading of heavy containers above light containers or at the top of a stack in a\ndeck stow? (V)\nGuide to Inspection\nHeavy on light can only be accepted when specifically permitted in the Cargo Securing Manual.\nIt is essential to avoid loading heavy containers over light, or at the top of a stack in a deck stow, unless specifically permitted in\nthe Cargo Securing Manual. This is because the securing system would normally have been designed on the assumption that\nlight containers are stowed on top. Stowage may allow for ‘heavy-heavy-light’; however, loading ‘heavy-medium-medium’ may\nresult in the same stack weight but would produce different strain on the securing system, especially if the GM is high.\n(A Master Guide to: Container Securing, 2012)\nLoading heavy containers top stow may cause stability problem and excessive lashing strains during ship’s motions at sea.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.20","internal_question_no":"08D.020","question_sort_key":8402000.308,"question_text":"Is there recorded evidence to show that the lashing pattern from the Cargo Securing Manual has been provided to the terminal and is the information for the lashing pattern posted at the ship’s access?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":155,"source_page_end":155,"raw_source_text":"Is there recorded evidence to show that the lashing pattern from the Cargo Securing Manual has\nbeen provided to the terminal and is the information for the lashing pattern posted at the ship’s access? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.21","internal_question_no":"08D.021","question_sort_key":8402100.309,"question_text":"Had the Ballast Water Management Plan for the present port stay been executed?","guide_to_inspection":"Based on pre-loading plan information, the ship shall execute a ballast water management plan for the coming port stay. This\nincludes optimisation of ballast water distribution to allow for minimal discharges in port.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":155,"source_page_end":155,"raw_source_text":"Had the Ballast Water Management Plan for the present port stay been executed? (V)\nGuide to Inspection\nBased on pre-loading plan information, the ship shall execute a ballast water management plan for the coming port stay. This\nincludes optimisation of ballast water distribution to allow for minimal discharges in port.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.22","internal_question_no":"08D.022","question_sort_key":8402200.31,"question_text":"Is there documented evidence of carrying out spot checks of actual loading against loading plan?","guide_to_inspection":"During the loading operation, spot checking of the actual loading compared to the loading plan should be undertaken\nthroughout the cargo area, with particular attention paid to OOG, DG and reefer containers. Discrepancies should be resolved\nwith the terminal planner and stowage coordinator, paying due regard to the health and safety implications of any solution.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":155,"source_page_end":155,"raw_source_text":"Is there documented evidence of carrying out spot checks of actual loading against loading plan? (V)\nGuide to Inspection\nDuring the loading operation, spot checking of the actual loading compared to the loading plan should be undertaken\nthroughout the cargo area, with particular attention paid to OOG, DG and reefer containers. Discrepancies should be resolved\nwith the terminal planner and stowage coordinator, paying due regard to the health and safety implications of any solution.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.23","internal_question_no":"08D.023","question_sort_key":8402300.311,"question_text":"Is there documented evidence of signing off completed lashing per bay and is all lashing gear used compatible with the lashing plan?","guide_to_inspection":"The lashing arrangement of each bay should be inspected and adjusted if necessary, by the crew following completion of work\nby the terminal personnel. (Safe Transport of Containers by Sea-Guidelines on Best Practices, 2008)\nAll gear should be uniformly compatible with the lashing plan, i.e., all twist locks of the same type, semi-automatic twist locks\nused with suitable lashing bars.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":156,"source_page_end":156,"raw_source_text":"Is there documented evidence of signing off completed lashing per bay and is all lashing gear\nused compatible with the lashing plan? (V)\nGuide to Inspection\nThe lashing arrangement of each bay should be inspected and adjusted if necessary, by the crew following completion of work\nby the terminal personnel. (Safe Transport of Containers by Sea-Guidelines on Best Practices, 2008)\nAll gear should be uniformly compatible with the lashing plan, i.e., all twist locks of the same type, semi-automatic twist locks\nused with suitable lashing bars.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.24","internal_question_no":"08D.024","question_sort_key":8402400.312,"question_text":"Is the bridge visibility condition for the next port confirmed?","guide_to_inspection":"Bridge visibility rules accordance with SOLAS must be observed and checked. In order to confirm sufficient visibility conditions,\na check of the arrival conditions for the next port should also be made.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":156,"source_page_end":156,"raw_source_text":"Is the bridge visibility condition for the next port confirmed? (V)\nGuide to Inspection\nBridge visibility rules accordance with SOLAS must be observed and checked. In order to confirm sufficient visibility conditions,\na check of the arrival conditions for the next port should also be made.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.25","internal_question_no":"08D.025","question_sort_key":8402500.313,"question_text":"Is there evidence to show that evaluation of forces acting on the containers have been calculated and the correct cargo-securing devices are being used to secure the containers to the ship?","guide_to_inspection":"An evaluation of forces acting on cargo units shall be incorporated in the Cargo Securing Manual and contain the following\ninformation:\n> Tables or diagrams giving a broad outline of the accelerations which can be expected in various positions on board the\nship in adverse sea conditions and with a range of applicable metacentric height (GM) values.\n> Examples of the forces acting on typical cargo units when subjected to the accelerations referred to in paragraph 3.2.1\nof MSC/Circ.745 and angles of roll and metacentric height (GM) values above which the forces acting on the cargo units\nexceed the permissible limit for the specified securing arrangements as far as practicable.\n> Examples of how to calculate number and strength of portable securing devices required to counteract the forces referred\nto in 3.2.2 of MSC/Circ.745 as well as safety factors to be used for different types of portable cargo securing devices.\nCalculations may be carried out according to Annex 13 to the CSS Code or methods accepted by the Administration.\n> It is recommended that the designer of a Cargo Securing Manual converts the calculation method used into a form suiting\nthe particular ship, its securing devices and the cargo carried. This form may consist of applicable diagrams, tables, or\ncalculated examples; and\n> Other operational arrangements such as electronic data processing (EDP) or use of a loading computer may be accepted\nas alternatives to the requirements of paragraphs 3.2.1 to 3.2.4 of MSC/Circ.745, providing that this system contains the\nsame information.\nIt is important that securing devices meet acceptable functional and strength criteria applicable to the ship and its cargo. It\nis also important that the officers on board are aware of the magnitude and direction of the forces involved and the correct\napplication and limitations of the cargo-securing devices. The crew and other persons employed for the securing of cargoes\nshould be instructed in the correct application and use of the cargo securing devices on board the ship. ‘Maximum Securing\nLoad (MSL)’ is a term used to define the allowable load capacity for a device used to secure cargo to a ship. ‘Safe Working Load\n(SWL)’ may be substituted for MSL for securing purposes, provided this is equal to or exceeds the strength defined by MSL.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":156,"source_page_end":156,"raw_source_text":"Is there evidence to show that evaluation of forces acting on the containers have been calculated\nand the correct cargo-securing devices are being used to secure the containers to the ship? (V)\nGuide to Inspection\nAn evaluation of forces acting on cargo units shall be incorporated in the Cargo Securing Manual and contain the following\ninformation:\n> Tables or diagrams giving a broad outline of the accelerations which can be expected in various positions on board the\nship in adverse sea conditions and with a range of applicable metacentric height (GM) values.\n> Examples of the forces acting on typical cargo units when subjected to the accelerations referred to in paragraph 3.2.1\nof MSC/Circ.745 and angles of roll and metacentric height (GM) values above which the forces acting on the cargo units\nexceed the permissible limit for the specified securing arrangements as far as practicable.\n> Examples of how to calculate number and strength of portable securing devices required to counteract the forces referred\nto in 3.2.2 of MSC/Circ.745 as well as safety factors to be used for different types of portable cargo securing devices.\nCalculations may be carried out according to Annex 13 to the CSS Code or methods accepted by the Administration.\n> It is recommended that the designer of a Cargo Securing Manual converts the calculation method used into a form suiting\nthe particular ship, its securing devices and the cargo carried. This form may consist of applicable diagrams, tables, or\ncalculated examples; and\n> Other operational arrangements such as electronic data processing (EDP) or use of a loading computer may be accepted\nas alternatives to the requirements of paragraphs 3.2.1 to 3.2.4 of MSC/Circ.745, providing that this system contains the\nsame information.\nIt is important that securing devices meet acceptable functional and strength criteria applicable to the ship and its cargo. It\nis also important that the officers on board are aware of the magnitude and direction of the forces involved and the correct\napplication and limitations of the cargo-securing devices. The crew and other persons employed for the securing of cargoes\nshould be instructed in the correct application and use of the cargo securing devices on board the ship. ‘Maximum Securing\nLoad (MSL)’ is a term used to define the allowable load capacity for a device used to secure cargo to a ship. ‘Safe Working Load\n(SWL)’ may be substituted for MSL for securing purposes, provided this is equal to or exceeds the strength defined by MSL.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.26","internal_question_no":"08D.026","question_sort_key":8402600.314,"question_text":"Is there documented evidence that lashings were tightened after departure once the lashings and containers settled in?","guide_to_inspection":"It is good practice to verify the tightening of the lashing after departure once the lashing and containers have settled in. This is\nespecially the case before ocean crossings, after receipt of bad weather outlooks, and after bad weather has been encountered\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)\nLashings should be checked and tightened within 24 hours after leaving port and regularly thereafter. This is especially true\nbefore the onset of bad weather.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":156,"source_page_end":156,"raw_source_text":"Is there documented evidence that lashings were tightened after departure once the lashings\nand containers settled in? (V)\nGuide to Inspection\nIt is good practice to verify the tightening of the lashing after departure once the lashing and containers have settled in. This is\nespecially the case before ocean crossings, after receipt of bad weather outlooks, and after bad weather has been encountered\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)\nLashings should be checked and tightened within 24 hours after leaving port and regularly thereafter. This is especially true\nbefore the onset of bad weather.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.27","internal_question_no":"08D.027","question_sort_key":8402700.315,"question_text":"Have personnel engaged in cargo securing operations been provided with relevant training and familiarisation?","guide_to_inspection":"RightShip recommends that personnel engaged in cargo securing operations attend a formal training course.\nPersonnel engaged in cargo-securing operations should be trained in the lashing and unlashing of containers as necessary to\ncarry out their duties in a safe manner. This should include the different types of lashing equipment that are expected to be used.\n> Personnel engaged in cargo-securing operations should be trained in the identification and handling of bad order or\ndefective securing gear in accordance with each ship’s procedures, to ensure damaged gear is segregated for repair and\nmaintenance or disposal.\n> Personnel engaged in cargo-securing operations should be trained to develop the knowledge and mental and physical\nmanual handling skills that they require to do their job safely and efficiently, and to develop general safety awareness to\nrecognise and avoid potential dangers.\n> Personnel should be trained in safe systems of work. Where personnel are involved in working at heights, they should be\ntrained in the use of relevant equipment. Where practical, the use of fall-protection equipment should take precedence over\nfall-arrest systems.\n> Personnel who are required to handle thermal cables and/or connect and disconnect temperature control units should be\ngiven training in recognising defective cables, receptacles, and plugs.\n> Personnel engaged in containership cargo operations should be familiar with the ship’s unique characteristics and\npotential hazards arising from such operations necessary to carry out their duties.\n(CSS code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":157,"source_page_end":157,"raw_source_text":"Have personnel engaged in cargo securing operations been provided with relevant training and familiarisation? (V)\nGuide to Inspection\nRightShip recommends that personnel engaged in cargo securing operations attend a formal training course.\nPersonnel engaged in cargo-securing operations should be trained in the lashing and unlashing of containers as necessary to\ncarry out their duties in a safe manner. This should include the different types of lashing equipment that are expected to be used.\n> Personnel engaged in cargo-securing operations should be trained in the identification and handling of bad order or\ndefective securing gear in accordance with each ship’s procedures, to ensure damaged gear is segregated for repair and\nmaintenance or disposal.\n> Personnel engaged in cargo-securing operations should be trained to develop the knowledge and mental and physical\nmanual handling skills that they require to do their job safely and efficiently, and to develop general safety awareness to\nrecognise and avoid potential dangers.\n> Personnel should be trained in safe systems of work. Where personnel are involved in working at heights, they should be\ntrained in the use of relevant equipment. Where practical, the use of fall-protection equipment should take precedence over\nfall-arrest systems.\n> Personnel who are required to handle thermal cables and/or connect and disconnect temperature control units should be\ngiven training in recognising defective cables, receptacles, and plugs.\n> Personnel engaged in containership cargo operations should be familiar with the ship’s unique characteristics and\npotential hazards arising from such operations necessary to carry out their duties.\n(CSS code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.28","internal_question_no":"08D.028","question_sort_key":8402800.316,"question_text":"Is the vessel equipped with sufficient portable radio equipment for use and has a direct radio communication capability been stablished between the terminal (planner, foreman, and watchman) and the ship duty’s officer?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":157,"source_page_end":157,"raw_source_text":"Is the vessel equipped with sufficient portable radio equipment for use and has a direct radio\ncommunication capability been stablished between the terminal (planner, foreman, and watchman)\nand the ship duty’s officer? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.29","internal_question_no":"08D.029","question_sort_key":8402900.317,"question_text":"Has an IMDG spotting plan been prepared, updated, and made available for emergency preparedness?","guide_to_inspection":"The IMDG spotting plan should be updated for emergency preparedness. Segregation requirements should be confirmed in\naccordance with the IMDG Code.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":157,"source_page_end":157,"raw_source_text":"Has an IMDG spotting plan been prepared, updated, and made available for emergency preparedness? (V)\nGuide to Inspection\nThe IMDG spotting plan should be updated for emergency preparedness. Segregation requirements should be confirmed in\naccordance with the IMDG Code.\n(Safe Transport of Containers by Sea - Guidelines on Best Practices, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.30","internal_question_no":"08D.030","question_sort_key":8403000.318,"question_text":"Is there a procedure for monitoring the temperature of refrigerated containers and are records maintained?","guide_to_inspection":"Regular monitoring and recording of the temperatures of the reefer containers should be carried out and properly documented.\nIn the event of a claim these can be compared against the reefer unit download data and shipper’s mobile temperature devices.\n(Refrigerated Containers, 2013)\nThe inspector shall record in comments if the reefer containers had been equipped with IoT Device. For additional information,\nreference should be made to the DCSA IoT data standard for remote Reefer container monitoring on board a vessel. Click here.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":157,"source_page_end":157,"raw_source_text":"Is there a procedure for monitoring the temperature of refrigerated containers and are\nrecords maintained? (V)\nGuide to Inspection\nRegular monitoring and recording of the temperatures of the reefer containers should be carried out and properly documented.\nIn the event of a claim these can be compared against the reefer unit download data and shipper’s mobile temperature devices.\n(Refrigerated Containers, 2013)\nThe inspector shall record in comments if the reefer containers had been equipped with IoT Device. For additional information,\nreference should be made to the DCSA IoT data standard for remote Reefer container monitoring on board a vessel. Click here.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.31","internal_question_no":"08D.031","question_sort_key":8403100.319,"question_text":"If refrigerated containers are carried, are sufficient spare parts available on board?","guide_to_inspection":"In the event of reefer container breakdowns, ships should have adequate spares on-board and the relevant skills to carry out\nemergency repairs to the reefer on-board.\nThe ship should also give prompt notification of reefer problems or malfunctions that cannot be repaired on board.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":157,"source_page_end":157,"raw_source_text":"If refrigerated containers are carried, are sufficient spare parts available on board? (V)\nGuide to Inspection\nIn the event of reefer container breakdowns, ships should have adequate spares on-board and the relevant skills to carry out\nemergency repairs to the reefer on-board.\nThe ship should also give prompt notification of reefer problems or malfunctions that cannot be repaired on board.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.32","internal_question_no":"08D.032","question_sort_key":8403200.32,"question_text":"If refrigerated containers are carried, is the electric power supply permanently installed from the engine room and are electric container sockets in good condition?","guide_to_inspection":"The ship’s electrical distribution system and container supply sockets should be in good working order and undamaged.\n(Refrigerated Containers, 2013)\nThe vessel’s manager shall use a Power Pack Unit (PPU) if the loading quantity of reefer cargo exceeds the ship’s power\ncapacity as indicated in the drawing and charter party. The PPU has an independent power supply and will not require the\nelectric power supply permanently installed from the vessel’s engine room.\nThe generator set shall be maintained in good working condition and free of oil leaks.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":158,"source_page_end":158,"raw_source_text":"If refrigerated containers are carried, is the electric power supply permanently installed from the engine\nroom and are electric container sockets in good condition? (V)\nGuide to Inspection\nThe ship’s electrical distribution system and container supply sockets should be in good working order and undamaged.\n(Refrigerated Containers, 2013)\nThe vessel’s manager shall use a Power Pack Unit (PPU) if the loading quantity of reefer cargo exceeds the ship’s power\ncapacity as indicated in the drawing and charter party. The PPU has an independent power supply and will not require the\nelectric power supply permanently installed from the vessel’s engine room.\nThe generator set shall be maintained in good working condition and free of oil leaks.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.33","internal_question_no":"08D.033","question_sort_key":8403300.321,"question_text":"Are officers familiar with the exothermic chain reaction and the stowage and segregation requirements for calcium hypochlorite in containers?","guide_to_inspection":"An exothermic reaction is a chemical reaction that releases energy through light or heat. An example of an exothermic reaction\nis a reaction between water and calcium chloride.\nThe incorrect stowage of exothermic dangerous goods such as calcium hypochlorite caused many fires in recent years.\nCalcium hypochlorite or calcium hypochlorite mixtures shall be transported in compliance with the stowage and segregation\nrequirements set out in the IMDG Code.\nIMDG Code Special Provision 314, under Part 3, Chapter 3.3, of the Code applies to calcium Hypochlorite.\nThe International Group of P&I Clubs and the Cargo Incident Notification System (CINS) document ‘Guidelines for the Carriage of\nCalcium Hypochlorite in Containers’ provides information for the carriage of calcium hypochlorite in containers.\n(Guidelines for the Carriage of Calcium Hypochlorite in Containers, 2018)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":158,"source_page_end":158,"raw_source_text":"Are officers familiar with the exothermic chain reaction and the stowage and segregation\nrequirements for calcium hypochlorite in containers? (V)\nGuide to Inspection\nAn exothermic reaction is a chemical reaction that releases energy through light or heat. An example of an exothermic reaction\nis a reaction between water and calcium chloride.\nThe incorrect stowage of exothermic dangerous goods such as calcium hypochlorite caused many fires in recent years.\nCalcium hypochlorite or calcium hypochlorite mixtures shall be transported in compliance with the stowage and segregation\nrequirements set out in the IMDG Code.\nIMDG Code Special Provision 314, under Part 3, Chapter 3.3, of the Code applies to calcium Hypochlorite.\nThe International Group of P&I Clubs and the Cargo Incident Notification System (CINS) document ‘Guidelines for the Carriage of\nCalcium Hypochlorite in Containers’ provides information for the carriage of calcium hypochlorite in containers.\n(Guidelines for the Carriage of Calcium Hypochlorite in Containers, 2018)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.34","internal_question_no":"08D.034","question_sort_key":8403400.322,"question_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":158,"source_page_end":158,"raw_source_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.1","internal_question_no":"08E.001","question_sort_key":8500100.323,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":158,"source_page_end":158,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.2","internal_question_no":"08E.002","question_sort_key":8500200.324,"question_text":"Is the vessel provided with self-unloading isolation procedures?","guide_to_inspection":"The objectives of the ISM Code are to ensure safety at sea, prevention of human injury or loss of life, and avoidance of damage\nto the environment, in particular to the marine environment and to property.\n(ISM Code 2018)\nRightship recommends that the isolation procedures should be about the need to isolate, de-energise, lockout and tag-out\nthe system, with the aim of reducing the risk of death or injury during system inspections, repairs, maintenance, assessments,\nadjustments, or cleaning.\nThe isolation procedures shall incorporate the followings:\n> The isolation procedure, check list and risk assessment documented and accessible to the relevant crew on board.\n> Providing information, instruction and training to crew involved with the system.\n> Appointing a person as a supervisor to make sure the crew strictly follows isolation procedures.\nRightship recommends the vessel’s manager provide ship-specific procedures, detailing steps for isolating cargo equipment\nprior to maintenance.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":159,"source_page_end":159,"raw_source_text":"Is the vessel provided with self-unloading isolation procedures? (V)\nGuide to Inspection\nThe objectives of the ISM Code are to ensure safety at sea, prevention of human injury or loss of life, and avoidance of damage\nto the environment, in particular to the marine environment and to property.\n(ISM Code 2018)\nRightship recommends that the isolation procedures should be about the need to isolate, de-energise, lockout and tag-out\nthe system, with the aim of reducing the risk of death or injury during system inspections, repairs, maintenance, assessments,\nadjustments, or cleaning.\nThe isolation procedures shall incorporate the followings:\n> The isolation procedure, check list and risk assessment documented and accessible to the relevant crew on board.\n> Providing information, instruction and training to crew involved with the system.\n> Appointing a person as a supervisor to make sure the crew strictly follows isolation procedures.\nRightship recommends the vessel’s manager provide ship-specific procedures, detailing steps for isolating cargo equipment\nprior to maintenance.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.3","internal_question_no":"08E.003","question_sort_key":8500300.325,"question_text":"Have personnel engaged in the operation of the self-unloading system been provided with relevant training and familiarisation?","guide_to_inspection":"Rightship recommends officers and engineers attend a combined on-board/shore-based training course consisting of\ntheoretical and practical training. Theoretical training shall include the mechanical system, hydraulic system, electrical system,\nmaintenance, spare parts, function, trouble-shooting and normal and emergency operation. Practical training shall include\nhands-on training sessions and trouble-shooting different components.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":159,"source_page_end":159,"raw_source_text":"Have personnel engaged in the operation of the self-unloading system been provided with relevant\ntraining and familiarisation? (V)\nGuide to Inspection\nRightship recommends officers and engineers attend a combined on-board/shore-based training course consisting of\ntheoretical and practical training. Theoretical training shall include the mechanical system, hydraulic system, electrical system,\nmaintenance, spare parts, function, trouble-shooting and normal and emergency operation. Practical training shall include\nhands-on training sessions and trouble-shooting different components.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.4","internal_question_no":"08E.004","question_sort_key":8500400.326,"question_text":"Are the ship’s crew aware of the safe operating requirements of tunnel conveyor watertight bulkhead doors and/or watertight doors in tunnel conveyor room, where applicable, and is a record of inspections and maintenance available on board?","guide_to_inspection":"Doors provided to ensure the watertight integrity of internal openings which are used while at sea are to be sliding watertight\ndoors capable of being remotely closed from the bridge and are also to be operable locally from each side of the bulkhead.\nIndicators are to be provided at the control position showing whether the doors are open or closed, and an audible alarm is to be\nprovided at the door closure. The power, control and indicators are to be operable in the event of mains power failure. Particular\nattention is to be paid to minimising the effect of control system failure. Each power-operated sliding watertight door shall be\nprovided with an individual hand-operated mechanism. It shall be possible to open and close the door by hand at the door itself\nfrom both sides.\n(SOLAS 74,2020)\nAccess doors and access hatch covers normally closed at sea, intended to ensure the watertight integrity of internal openings,\nshall be provided with means of indication locally and on the bridge showing whether these doors or hatch covers are open or\nclosed. A notice is to be affixed to each such door or hatch cover to the effect that it is not to be left open. (SOLAS 74,2020)\nWoodchip carriers are installed shuttle conveyor and shuttle conveyor room. The shuttle conveyor swings out from the ship’s\nside hull through opened watertight doors. There should be evidence of watertightness testing of the watertight doors at regular\nintervals.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":159,"source_page_end":159,"raw_source_text":"Are the ship’s crew aware of the safe operating requirements of tunnel conveyor watertight bulkhead\ndoors and/or watertight doors in tunnel conveyor room, where applicable, and is a record of inspections\nand maintenance available on board? (V)\nGuide to Inspection\nDoors provided to ensure the watertight integrity of internal openings which are used while at sea are to be sliding watertight\ndoors capable of being remotely closed from the bridge and are also to be operable locally from each side of the bulkhead.\nIndicators are to be provided at the control position showing whether the doors are open or closed, and an audible alarm is to be\nprovided at the door closure. The power, control and indicators are to be operable in the event of mains power failure. Particular\nattention is to be paid to minimising the effect of control system failure. Each power-operated sliding watertight door shall be\nprovided with an individual hand-operated mechanism. It shall be possible to open and close the door by hand at the door itself\nfrom both sides.\n(SOLAS 74,2020)\nAccess doors and access hatch covers normally closed at sea, intended to ensure the watertight integrity of internal openings,\nshall be provided with means of indication locally and on the bridge showing whether these doors or hatch covers are open or\nclosed. A notice is to be affixed to each such door or hatch cover to the effect that it is not to be left open. (SOLAS 74,2020)\nWoodchip carriers are installed shuttle conveyor and shuttle conveyor room. The shuttle conveyor swings out from the ship’s\nside hull through opened watertight doors. There should be evidence of watertightness testing of the watertight doors at regular\nintervals.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.5","internal_question_no":"08E.005","question_sort_key":8500500.327,"question_text":"Are the officers and ratings aware of the location of the emergency stop devices; are the emergency stop devices in good order and is there recorded evidence of regular testing?","guide_to_inspection":"The emergency stop devices at each operator-controlled stations should be tested regularly to ensure that they are functioning\ncorrectly, and the result of these tests should be recorded.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":160,"source_page_end":160,"raw_source_text":"Are the officers and ratings aware of the location of the emergency stop devices; are the emergency\nstop devices in good order and is there recorded evidence of regular testing? (V)\nGuide to Inspection\nThe emergency stop devices at each operator-controlled stations should be tested regularly to ensure that they are functioning\ncorrectly, and the result of these tests should be recorded.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.6","internal_question_no":"08E.006","question_sort_key":8500600.328,"question_text":"Are light fittings in the tunnel conveyor Ex‘d’ rated and in good condition?","guide_to_inspection":"Ex ‘d’ ex-proof type of protection, which responds to the European standard EN 60079-1, is based on the concept of\ncontainment. In this mode of protection, the electrical equipment is enclosed in special boxes, designed to contain a possible\ninternal explosion and to prevent its transmission to the outside atmosphere.\nThe manufacturers or Administration’s certificate approving the fittings for use in gas-hazardous areas will be invalidated if the\ncorrect bolts for securing the cover, or the correct light bulb size, are not used.\nParticular attention should be paid to the following:\n> Cracks in metal, cracked or broken glass or failure of cement around cemented glass in flameproof or explosion-proof\nenclosures\n> Covers of flameproof enclosures to ensure that they are tight, that no bolts are missing, and that no gaskets are present\nbetween mating metal surfaces\n> Each connection to ensure that it is properly connected\n> Possible slackness of joints in conduit runs and fittings","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":160,"source_page_end":160,"raw_source_text":"Are light fittings in the tunnel conveyor Ex‘d’ rated and in good condition? (V)\nGuide to Inspection\nEx ‘d’ ex-proof type of protection, which responds to the European standard EN 60079-1, is based on the concept of\ncontainment. In this mode of protection, the electrical equipment is enclosed in special boxes, designed to contain a possible\ninternal explosion and to prevent its transmission to the outside atmosphere.\nThe manufacturers or Administration’s certificate approving the fittings for use in gas-hazardous areas will be invalidated if the\ncorrect bolts for securing the cover, or the correct light bulb size, are not used.\nParticular attention should be paid to the following:\n> Cracks in metal, cracked or broken glass or failure of cement around cemented glass in flameproof or explosion-proof\nenclosures\n> Covers of flameproof enclosures to ensure that they are tight, that no bolts are missing, and that no gaskets are present\nbetween mating metal surfaces\n> Each connection to ensure that it is properly connected\n> Possible slackness of joints in conduit runs and fittings","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.7","internal_question_no":"08E.007","question_sort_key":8500700.329,"question_text":"Are lights and warning devices of the self-unloading system regularly tested and the result recorded?","guide_to_inspection":"The inspector shall witness the testing of lights and warning devices where possible.\nTunnel rate lights, tunnel horn, deck horn, tunnel warning beacon, deck warning beacon and boom lighting and the end light (red\nflashing) of boom conveyor where applicable should be, tested regularly.\nThe electrical equipment inside the tunnel shall be intrinsically safe/explosion proof.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":160,"source_page_end":160,"raw_source_text":"Are lights and warning devices of the self-unloading system regularly tested and the result recorded? (V)\nGuide to Inspection\nThe inspector shall witness the testing of lights and warning devices where possible.\nTunnel rate lights, tunnel horn, deck horn, tunnel warning beacon, deck warning beacon and boom lighting and the end light (red\nflashing) of boom conveyor where applicable should be, tested regularly.\nThe electrical equipment inside the tunnel shall be intrinsically safe/explosion proof.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.8","internal_question_no":"08E.008","question_sort_key":8500800.33,"question_text":"Is there a procedure for suppression of dust during cargo operations?","guide_to_inspection":"Record a Finding if the method of dust suppression in the conveyor tunnel is not effective.\nRecord the type of suppression system that is employed on-board the ship.\nThere is always an element of dust produced by the product during cargo operation. Procedures, personnel protection and\neffective methods to suppress dust in the conveyor tunnel and on the boom conveyor shall be provided by the vessel’s manager.\nExample of methods used to suppress dust are:\n> Dry fog system\n> Water mist-spray system\n> Dust extraction system\n> Foam dust suppression system\n> Belt conveyors and boom conveyors were protected by cover– steel plates across the conveyors or portable ones for\nexample tarpaulin made.\nMaintenance of dust suppression systems shall be incorporated in the PMS as per manufacturer recommendation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":160,"source_page_end":160,"raw_source_text":"Is there a procedure for suppression of dust during cargo operations? (V)\nGuide to Inspection\nRecord a Finding if the method of dust suppression in the conveyor tunnel is not effective.\nRecord the type of suppression system that is employed on-board the ship.\nThere is always an element of dust produced by the product during cargo operation. Procedures, personnel protection and\neffective methods to suppress dust in the conveyor tunnel and on the boom conveyor shall be provided by the vessel’s manager.\nExample of methods used to suppress dust are:\n> Dry fog system\n> Water mist-spray system\n> Dust extraction system\n> Foam dust suppression system\n> Belt conveyors and boom conveyors were protected by cover– steel plates across the conveyors or portable ones for\nexample tarpaulin made.\nMaintenance of dust suppression systems shall be incorporated in the PMS as per manufacturer recommendation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.9","internal_question_no":"08E.009","question_sort_key":8500900.331,"question_text":"Is the belt cleaning system/scraper in good order and maintained as per manufacturer recommendation and is there evidence to show that the belt cleaners have been inspected regularly for proper function?","guide_to_inspection":"The necessary maintenance and repairs as per manufacturer recommendation shall be incorporated in the PMS.\nConveyor Skirt Boards are designed to secure material on conveyor belting and mitigate excessive spillage during cargo\noperations. The skirt board arrangement could consist of wooden boards, chute lining, worn belts, or skateboard rubber, and\nshould be maintained in good condition as per the manufacturer’s recommendations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":161,"source_page_end":161,"raw_source_text":"Is the belt cleaning system/scraper in good order and maintained as per manufacturer\nrecommendation and is there evidence to show that the belt cleaners have been inspected regularly\nfor proper function? (V)\nGuide to Inspection\nThe necessary maintenance and repairs as per manufacturer recommendation shall be incorporated in the PMS.\nConveyor Skirt Boards are designed to secure material on conveyor belting and mitigate excessive spillage during cargo\noperations. The skirt board arrangement could consist of wooden boards, chute lining, worn belts, or skateboard rubber, and\nshould be maintained in good condition as per the manufacturer’s recommendations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.10","internal_question_no":"08E.010","question_sort_key":8501000.332,"question_text":"Are the belt speed- sensors, belt scales and slip detecting device, where applicable, in good order and maintained as per manufacturer recommendations?","guide_to_inspection":"A belt scale is used to measure the flow rate of the cargo.\nThe vessel’s manager shall provide guidelines for selecting various belt speed and discharge rates and precautions to avoid\noverloading the self-unloading system.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":161,"source_page_end":161,"raw_source_text":"Are the belt speed- sensors, belt scales and slip detecting device, where applicable, in good order\nand maintained as per manufacturer recommendations? (V)\nGuide to Inspection\nA belt scale is used to measure the flow rate of the cargo.\nThe vessel’s manager shall provide guidelines for selecting various belt speed and discharge rates and precautions to avoid\noverloading the self-unloading system.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.11","internal_question_no":"08E.011","question_sort_key":8501100.333,"question_text":"Are the cargo hold discharge gates and watertight doors clearly marked to indicate the hold and spaces they serve?","guide_to_inspection":"Rightship recommends that the ship shall be provided with the hold discharging gates and watertight doors identification\nnumbers used in the loading or unloading plan. The location, size and colour of these numbers should be chosen so that they\nare clearly visible to the cargo-gate operators.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":161,"source_page_end":161,"raw_source_text":"Are the cargo hold discharge gates and watertight doors clearly marked to indicate the hold\nand spaces they serve? (V)\nGuide to Inspection\nRightship recommends that the ship shall be provided with the hold discharging gates and watertight doors identification\nnumbers used in the loading or unloading plan. The location, size and colour of these numbers should be chosen so that they\nare clearly visible to the cargo-gate operators.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.12","internal_question_no":"08E.012","question_sort_key":8501200.334,"question_text":"Has the hydraulic oil of the self-unloading system been tested regularly for contamination and deterioration as per manufacturer recommendation?","guide_to_inspection":"Monitoring hydraulics with oil analysis is the only way to establish whether the hydraulic fluid is impacting the anticipated\nperformance. Contamination is the main cause of failure, typically water contamination or dirt ingression. In addition to the\nElemental and Contaminant tests, the hydraulic oil of the self-unloading system shall also be subjected to a Particle Count test.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":161,"source_page_end":161,"raw_source_text":"Has the hydraulic oil of the self-unloading system been tested regularly for contamination and\ndeterioration as per manufacturer recommendation? (M)\nGuide to Inspection\nMonitoring hydraulics with oil analysis is the only way to establish whether the hydraulic fluid is impacting the anticipated\nperformance. Contamination is the main cause of failure, typically water contamination or dirt ingression. In addition to the\nElemental and Contaminant tests, the hydraulic oil of the self-unloading system shall also be subjected to a Particle Count test.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.13","internal_question_no":"08E.013","question_sort_key":8501300.335,"question_text":"Are the tunnel-conveyor emergency stop, speed switch, and belt misalignment switch in good order and inspected regularly?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":161,"source_page_end":161,"raw_source_text":"Are the tunnel-conveyor emergency stop, speed switch, and belt misalignment switch in good\norder and inspected regularly? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.14","internal_question_no":"08E.014","question_sort_key":8501400.336,"question_text":"Is the tunnel-conveyor hydraulic system arrangement in good condition and free from oil leakage?","guide_to_inspection":"The pipelines, valves and shafts should be in good condition. If there is evidence of oil leakage this must be recorded as a\nFinding.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":161,"source_page_end":161,"raw_source_text":"Is the tunnel-conveyor hydraulic system arrangement in good condition and free from oil leakage? (V)\nGuide to Inspection\nThe pipelines, valves and shafts should be in good condition. If there is evidence of oil leakage this must be recorded as a\nFinding.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.15","internal_question_no":"08E.015","question_sort_key":8501500.337,"question_text":"Are boom dust cover, spill tray and telescopic chute arrangements, where applicable, adequate?","guide_to_inspection":"The belt and boom conveyors shall be covered by fixed and/or portable means, i.e. fixed steel plate across the conveyors or\nportable type, for example made of tarpaulin.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Are boom dust cover, spill tray and telescopic chute arrangements, where applicable, adequate? (V)\nGuide to Inspection\nThe belt and boom conveyors shall be covered by fixed and/or portable means, i.e. fixed steel plate across the conveyors or\nportable type, for example made of tarpaulin.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.16","internal_question_no":"08E.016","question_sort_key":8501600.338,"question_text":"Has the sequence of the cargo plan been followed by the cargo-gate operators, and is the movement of the cargo-gate operators reported to the duty officer and is there evidence to confirm that movement of cargo-gate operators has been monitored to ensure compliance with the cargo plan?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Has the sequence of the cargo plan been followed by the cargo-gate operators, and is the movement\nof the cargo-gate operators reported to the duty officer and is there evidence to confirm that movement\nof cargo-gate operators has been monitored to ensure compliance with the cargo plan? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.17","internal_question_no":"08E.017","question_sort_key":8501700.339,"question_text":"Is the vibrator system in good order and is there recorded evidence of regular inspection as per manufacturer recommendations?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Is the vibrator system in good order and is there recorded evidence of regular inspection as per\nmanufacturer recommendations? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.18","internal_question_no":"08E.018","question_sort_key":8501800.34,"question_text":"Is the lift conveyor in good order, free of corrosion, damage and leakage and is the spillage chute of the lift conveyor, where applicable, collecting the cargo spillage effectively?","guide_to_inspection":"Any cargo spillage from the cleats shall be collected in the spillage chute, located near the base of the vertical belt, and directed\nback onto the belt.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Is the lift conveyor in good order, free of corrosion, damage and leakage and is the spillage chute\nof the lift conveyor, where applicable, collecting the cargo spillage effectively? (V)\nGuide to Inspection\nAny cargo spillage from the cleats shall be collected in the spillage chute, located near the base of the vertical belt, and directed\nback onto the belt.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.19","internal_question_no":"08E.019","question_sort_key":8501900.341,"question_text":"Are walk-rounds of the entire system carried out regularly, recorded and are the staff conducting the rounds aware of their duties?","guide_to_inspection":"A walk around checklist that covers the most important aspect of the check should be incorporated in the SMS. There should\nbe a field inspection patrol schedule developed to detect any conditions or components that need attention.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Are walk-rounds of the entire system carried out regularly, recorded and are the staff conducting\nthe rounds aware of their duties? (V)\nGuide to Inspection\nA walk around checklist that covers the most important aspect of the check should be incorporated in the SMS. There should\nbe a field inspection patrol schedule developed to detect any conditions or components that need attention.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.20","internal_question_no":"08E.020","question_sort_key":8502000.342,"question_text":"Is the condition of belt tension checked during cargo operations and is there evidence to show that the belt tension and alignment is inspected regularly for proper function?","guide_to_inspection":"Material spillage from the loop belt may be as a result of incorrect belt alignment and low belt tension. The belt shall not move in\na zigzag direction.\nThe operational hours of the conveyor belt should be logged, and essential maintenance tasks, including alignment and\nreplacement of the conveyor belt, should be carried out according to the manufacturer’s recommendations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Is the condition of belt tension checked during cargo operations and is there evidence to show\nthat the belt tension and alignment is inspected regularly for proper function? (V)\nGuide to Inspection\nMaterial spillage from the loop belt may be as a result of incorrect belt alignment and low belt tension. The belt shall not move in\na zigzag direction.\nThe operational hours of the conveyor belt should be logged, and essential maintenance tasks, including alignment and\nreplacement of the conveyor belt, should be carried out according to the manufacturer’s recommendations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.21","internal_question_no":"08E.021","question_sort_key":8502100.343,"question_text":"Are the tunnel trash pumping and disposal arrangements in good order and is the overboard valve provided with a notice warning against discharge of oil or oily mixture?","guide_to_inspection":"The trash pumps are provided at the tunnel bilge wells and are also capable of pumping out trash.\nThe accumulated water inside the tunnel may be contaminated. The water may consist of oil from hydraulic oil leaks that may\noccur at each unloading or contain cargo residue.\nAdequate arrangements should be in place for the disposal of water from the tunnel conveyor. The bilge strum box shall be\nclean and free of cargo residue.\nCare must be taken to ensure that the water is free of contamination before disposal.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":162,"source_page_end":162,"raw_source_text":"Are the tunnel trash pumping and disposal arrangements in good order and is the overboard\nvalve provided with a notice warning against discharge of oil or oily mixture? (V)\nGuide to Inspection\nThe trash pumps are provided at the tunnel bilge wells and are also capable of pumping out trash.\nThe accumulated water inside the tunnel may be contaminated. The water may consist of oil from hydraulic oil leaks that may\noccur at each unloading or contain cargo residue.\nAdequate arrangements should be in place for the disposal of water from the tunnel conveyor. The bilge strum box shall be\nclean and free of cargo residue.\nCare must be taken to ensure that the water is free of contamination before disposal.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.22","internal_question_no":"08E.022","question_sort_key":8502200.344,"question_text":"Is a water-level alarm system provided for the tunnel bilge well, and is the alarm system regularly tested and the result recorded?","guide_to_inspection":"The inspector should test the bilge-well high-water-level audible and visual alarms when possible.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":163,"source_page_end":163,"raw_source_text":"Is a water-level alarm system provided for the tunnel bilge well, and is the alarm system regularly\ntested and the result recorded? (V)\nGuide to Inspection\nThe inspector should test the bilge-well high-water-level audible and visual alarms when possible.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.23","internal_question_no":"08E.023","question_sort_key":8502300.345,"question_text":"Is the boom conveyor in good order, free of corrosion, damage, and oil leakage?","guide_to_inspection":"The maintenance and inspection of slewing and luffing components shall be incorporated in the PMS as per manufacturer\nrecommendation. Baffle plates should be intact, in good condition and free of damage, deformation and holed. The boom\nplatform and railing should be maintained in good order.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":163,"source_page_end":163,"raw_source_text":"Is the boom conveyor in good order, free of corrosion, damage, and oil leakage? (V)\nGuide to Inspection\nThe maintenance and inspection of slewing and luffing components shall be incorporated in the PMS as per manufacturer\nrecommendation. Baffle plates should be intact, in good condition and free of damage, deformation and holed. The boom\nplatform and railing should be maintained in good order.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.24","internal_question_no":"08E.024","question_sort_key":8502400.346,"question_text":"Are the boom conveyor and /or shuttle conveyor, where applicable, walkway lights and floodlights in good working condition?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":163,"source_page_end":163,"raw_source_text":"Are the boom conveyor and /or shuttle conveyor, where applicable, walkway lights and floodlights\nin good working condition? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.25","internal_question_no":"08E.025","question_sort_key":8502500.347,"question_text":"Is all electric equipment including cable box, cable run and cable tray and shore interlock connection system on the boom conveyor in good order?","guide_to_inspection":"The shore connection system links to shore conveyor and it makes the ship’s conveyor to stop if shore or ship’s conveyor stop.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":163,"source_page_end":163,"raw_source_text":"Is all electric equipment including cable box, cable run and cable tray and shore interlock\nconnection system on the boom conveyor in good order? (V)\nGuide to Inspection\nThe shore connection system links to shore conveyor and it makes the ship’s conveyor to stop if shore or ship’s conveyor stop.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.26","internal_question_no":"08E.026","question_sort_key":8502600.348,"question_text":"Are the officers aware of the slewing/swing out limits of the boom conveyor/shuttle conveyor and is there recorded evidence of verification of function of slew/luff limit switch?","guide_to_inspection":"Inspector shall review the evidence of regular testing and maintenance of the limit switches.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":163,"source_page_end":163,"raw_source_text":"Are the officers aware of the slewing/swing out limits of the boom conveyor/shuttle conveyor\nand is there recorded evidence of verification of function of slew/luff limit switch? (V)\nGuide to Inspection\nInspector shall review the evidence of regular testing and maintenance of the limit switches.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.27","internal_question_no":"08E.027","question_sort_key":8502700.349,"question_text":"Are the idlers and return rolls of the self-unloading system free from build-up material and are they rotating freely?","guide_to_inspection":"Idlers and return rolls should be checked for material build-up and freeness of rotation. Rollers can be overheated due to either a\nbearing failure or to being jammed with refuse and overheating causing and sustaining a fire for a period of time.\nThe vessel should carry a sufficient quantity of spare parts.\nThe rollers grease fittings should be in place and in good order. The recommendation of manufacturer for selection, application\nand replenishment of correct lubricant shall be followed.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":163,"source_page_end":163,"raw_source_text":"Are the idlers and return rolls of the self-unloading system free from build-up material and are\nthey rotating freely? (V)\nGuide to Inspection\nIdlers and return rolls should be checked for material build-up and freeness of rotation. Rollers can be overheated due to either a\nbearing failure or to being jammed with refuse and overheating causing and sustaining a fire for a period of time.\nThe vessel should carry a sufficient quantity of spare parts.\nThe rollers grease fittings should be in place and in good order. The recommendation of manufacturer for selection, application\nand replenishment of correct lubricant shall be followed.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.28","internal_question_no":"08E.028","question_sort_key":8502800.35,"question_text":"Is the ventilation system of the tunnel area in order, and is there documented evidence to confirm that the ventilators are working to their operational capacity?","guide_to_inspection":"The wearing of paper face masks by operators inside the tunnel proves poor air quality. Record a Finding if the quality of air\ninside the tunnel was poor. Record in comments whether the vessel was equipped with dust- removal or air-filtration system.\nRightShip recommends that capacity of ventilation system checked regularly, and fans were operating to capacity.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":164,"source_page_end":164,"raw_source_text":"Is the ventilation system of the tunnel area in order, and is there documented evidence to confirm\nthat the ventilators are working to their operational capacity? (V)\nGuide to Inspection\nThe wearing of paper face masks by operators inside the tunnel proves poor air quality. Record a Finding if the quality of air\ninside the tunnel was poor. Record in comments whether the vessel was equipped with dust- removal or air-filtration system.\nRightShip recommends that capacity of ventilation system checked regularly, and fans were operating to capacity.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.29","internal_question_no":"08E.029","question_sort_key":8502900.351,"question_text":"Is the tunnel area clean free from refuse and is the overall standard of housekeeping satisfactory?","guide_to_inspection":"Particular attention should be paid to any loose items which may fall on the belt and damage the belt or hoppers between the belts.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":164,"source_page_end":164,"raw_source_text":"Is the tunnel area clean free from refuse and is the overall standard of housekeeping satisfactory? (V)\nGuide to Inspection\nParticular attention should be paid to any loose items which may fall on the belt and damage the belt or hoppers between the belts.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.30","internal_question_no":"08E.030","question_sort_key":8503000.352,"question_text":"Is the vessel is provided with guidelines for ‘the prevention, early detection and suppression of fire in the cargo conveyor tunnel’ and are the crew familiar with the guidelines?","guide_to_inspection":"Rightship recommends shipowners consider fitting a remote fire-fighting system in the tunnel and associated areas.\nRecord in comments whether the cargo conveyor tunnel was protected with a fixed fire detection and fire extinguisher system.\nRisk of fire shall be controlled by regular monitoring to ensure effectiveness of control measures taken with respect to potential\nignition sources. If the vessel was provided with a fixed fire-detection and firefighting system, the inspector shall review the\ndocumented evidence of regular checks.\nExcept for ro-ro and vehicle spaces, cargo spaces on cargo ships of 2000 gross tonnage and upwards shall be protected by a fixed\ncarbon dioxide or inert gas fire-extinguisher system complying with the provisions of the Fire Safety System Code, or by a fire-\nextinguishing system which gives equivalent protection.\nThe administration may exempt from the requirements of paragraphs 7.1.3 and 7.2 cargo spaces of any cargo ship if constructed,\nand solely intended, for the carriage of ore, coal, grain, unseasoned timber, non-combustible cargoes or cargoes which, in the\nopinion of the Administration, constitute a low fire risk. Such exemptions may be granted only if the ship is fitted with steel hatch\ncovers and effective means of closing all ventilators and other openings leading to cargo spaces. When such exemptions are\ngranted, the administration shall issue an Exemption Certificate, irrespective of the date of construction of the ship concerned,\nin accordance with regulation 1/12(a)(vi) and shall ensure that the list of cargoes the ship is permitted to carry is attached to the\nExemption Certificate.\n(SOLAS 74,2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":164,"source_page_end":164,"raw_source_text":"Is the vessel is provided with guidelines for ‘the prevention, early detection and suppression of\nfire in the cargo conveyor tunnel’ and are the crew familiar with the guidelines? (V)\nGuide to Inspection\nRightship recommends shipowners consider fitting a remote fire-fighting system in the tunnel and associated areas.\nRecord in comments whether the cargo conveyor tunnel was protected with a fixed fire detection and fire extinguisher system.\nRisk of fire shall be controlled by regular monitoring to ensure effectiveness of control measures taken with respect to potential\nignition sources. If the vessel was provided with a fixed fire-detection and firefighting system, the inspector shall review the\ndocumented evidence of regular checks.\nExcept for ro-ro and vehicle spaces, cargo spaces on cargo ships of 2000 gross tonnage and upwards shall be protected by a fixed\ncarbon dioxide or inert gas fire-extinguisher system complying with the provisions of the Fire Safety System Code, or by a fire-\nextinguishing system which gives equivalent protection.\nThe administration may exempt from the requirements of paragraphs 7.1.3 and 7.2 cargo spaces of any cargo ship if constructed,\nand solely intended, for the carriage of ore, coal, grain, unseasoned timber, non-combustible cargoes or cargoes which, in the\nopinion of the Administration, constitute a low fire risk. Such exemptions may be granted only if the ship is fitted with steel hatch\ncovers and effective means of closing all ventilators and other openings leading to cargo spaces. When such exemptions are\ngranted, the administration shall issue an Exemption Certificate, irrespective of the date of construction of the ship concerned,\nin accordance with regulation 1/12(a)(vi) and shall ensure that the list of cargoes the ship is permitted to carry is attached to the\nExemption Certificate.\n(SOLAS 74,2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.31","internal_question_no":"08E.031","question_sort_key":8503100.353,"question_text":"Does the vessel stability information provide guidance for shipboard personnel on the effect of flooding the tunnel?","guide_to_inspection":"The introduction of water into the tunnel in order to submerge the conveyor system in case of fire creates a free surface area\nwhich, under the sheltered conditions of the harbour where there is no motion of the ship, presents little danger of significant\nstability loss. Under different circumstances, where motion could be imparted by external forces, such as wind and seas or by\na cargo shift, and particularly if at sea when subject to rolling and pitching, the dynamic surging of the water will not only cause\nmassive adverse effects on stability but can also cause considerable structural damage.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":164,"source_page_end":164,"raw_source_text":"Does the vessel stability information provide guidance for shipboard personnel on the effect of\nflooding the tunnel? (V)\nGuide to Inspection\nThe introduction of water into the tunnel in order to submerge the conveyor system in case of fire creates a free surface area\nwhich, under the sheltered conditions of the harbour where there is no motion of the ship, presents little danger of significant\nstability loss. Under different circumstances, where motion could be imparted by external forces, such as wind and seas or by\na cargo shift, and particularly if at sea when subject to rolling and pitching, the dynamic surging of the water will not only cause\nmassive adverse effects on stability but can also cause considerable structural damage.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.32","internal_question_no":"08E.032","question_sort_key":8503200.354,"question_text":"If the electric voltage power of vessel is greater than 1000 volts (high voltage), is staff suitably trained?","guide_to_inspection":"Record in comment which officers have undergone Shipboard High Voltage Training and the nature of such training.\nA vessel equipped with high voltage systems above 1,000 volts should have on board certificated engineer officers as per STCW\nTable A-III/2 of chapter. Holders of a Certificate of Competency of Electro-technical officer according to regulations III/6 of the\nannex to the STCW-Convention fulfil this requirement.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":165,"source_page_end":165,"raw_source_text":"If the electric voltage power of vessel is greater than 1000 volts (high voltage), is staff suitably trained? (V)\nGuide to Inspection\nRecord in comment which officers have undergone Shipboard High Voltage Training and the nature of such training.\nA vessel equipped with high voltage systems above 1,000 volts should have on board certificated engineer officers as per STCW\nTable A-III/2 of chapter. Holders of a Certificate of Competency of Electro-technical officer according to regulations III/6 of the\nannex to the STCW-Convention fulfil this requirement.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08E","section_number":8,"section_letter":"E","section_title":"Cargo Operation - Self-Unloading Transshipment","printed_question_no":"8.33","internal_question_no":"08E.033","question_sort_key":8503300.355,"question_text":"Is the vessel equipped with sufficient intrinsically safe portable radios for use inside the tunnel and, are the radio ‘dead zones’ within tunnel identified and safeguards put in place?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":165,"source_page_end":165,"raw_source_text":"Is the vessel equipped with sufficient intrinsically safe portable radios for use inside the tunnel\nand, are the radio ‘dead zones’ within tunnel identified and safeguards put in place? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.1","internal_question_no":"08F.001","question_sort_key":8600100.356,"question_text":"Has the final lifting and rigging plan been developed and documented as the procedure for the safe lifting of heavy cargo?","guide_to_inspection":"For any heavy lift, it is crucial to develop and document a lifting and rigging plan. This plan should outline the procedures for\nthe lift and include precise information regarding the centre of gravity of the unit, the intended lifting spread to be used, and the\ncalculations for rigging stability, often referred to as the lifting triangle.\nThe plan should include a defined method for assessing vessel stability. The following recommended approach is provided for\nconsideration:\n> For the initial stability check: virtual centre of gravity or Kaps method,\n> For two-chain suspensions: Nikitib method,\n> For detailed and critical lifts: numerical simulation.\nIt is crucial to assess all the disturbing factors, including wind, rigging tolerances, crane movement, vessel movement, shifts in\nthe centre of gravity, steering line forces, and friction at lift points.\nFor every heavy lift, the wind is an important factor for the safety of the operation. The maximum acceptable limits of wind\nspeed are typically established through experience or by following established guidelines. To analyse the impact on the stability\nof lifts, various analytical formulas may be utilised to calculate the forces acting on the lifted structure and the resultant tilt\nangles of the suspended rigging arrangement.\nThe calculations for the wind profile, which include the logarithmic profile with a reference height of 10 metres, as well as the\nforce equations, should be executed with accuracy, ensuring that conservative limits are set.\nThe plan should clearly define the operational wind and weather limits by detailing the maximum Beaufort scale or specific wind\nspeeds, and this information should be thoroughly documented in each lifting and rigging plan.\nThe sliding and tilt angles should be determined for each shape—flat, cylindrical, conical, and box—utilising conservative friction\ncoefficients.\nThe stability assessment should consider vessel motions and heel effects by examining vessel pitch and roll, as well as changes\nin trim and heel, and their influence on GM and GZ curves.\nThe plan should specify the rigging tolerances, SWL, MBL, and friction values. Furthermore, load assumptions, such as SWL,\nMBL, friction factors, and tolerance ranges, should be documented clearly.\nFor further information, reference should be made to the Guidance on Stability of Lifts(click here), which provides an overview of\nmethods for assessing the stability of lifting arrangements.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":165,"source_page_end":165,"raw_source_text":"Has the final lifting and rigging plan been developed and documented as the procedure for the safe lifting of heavy cargo? (V)\nGuide to Inspection\nFor any heavy lift, it is crucial to develop and document a lifting and rigging plan. This plan should outline the procedures for\nthe lift and include precise information regarding the centre of gravity of the unit, the intended lifting spread to be used, and the\ncalculations for rigging stability, often referred to as the lifting triangle.\nThe plan should include a defined method for assessing vessel stability. The following recommended approach is provided for\nconsideration:\n> For the initial stability check: virtual centre of gravity or Kaps method,\n> For two-chain suspensions: Nikitib method,\n> For detailed and critical lifts: numerical simulation.\nIt is crucial to assess all the disturbing factors, including wind, rigging tolerances, crane movement, vessel movement, shifts in\nthe centre of gravity, steering line forces, and friction at lift points.\nFor every heavy lift, the wind is an important factor for the safety of the operation. The maximum acceptable limits of wind\nspeed are typically established through experience or by following established guidelines. To analyse the impact on the stability\nof lifts, various analytical formulas may be utilised to calculate the forces acting on the lifted structure and the resultant tilt\nangles of the suspended rigging arrangement.\nThe calculations for the wind profile, which include the logarithmic profile with a reference height of 10 metres, as well as the\nforce equations, should be executed with accuracy, ensuring that conservative limits are set.\nThe plan should clearly define the operational wind and weather limits by detailing the maximum Beaufort scale or specific wind\nspeeds, and this information should be thoroughly documented in each lifting and rigging plan.\nThe sliding and tilt angles should be determined for each shape—flat, cylindrical, conical, and box—utilising conservative friction\ncoefficients.\nThe stability assessment should consider vessel motions and heel effects by examining vessel pitch and roll, as well as changes\nin trim and heel, and their influence on GM and GZ curves.\nThe plan should specify the rigging tolerances, SWL, MBL, and friction values. Furthermore, load assumptions, such as SWL,\nMBL, friction factors, and tolerance ranges, should be documented clearly.\nFor further information, reference should be made to the Guidance on Stability of Lifts(click here), which provides an overview of\nmethods for assessing the stability of lifting arrangements.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.2","internal_question_no":"08F.002","question_sort_key":8600200.357,"question_text":"Was a specific risk assessment provided for the heavy lift vessel, and are all lifting operations formally risk assessed?","guide_to_inspection":"The inspector should record a Finding if any task was initiated when the residual risk rating, after implementing all control\nmeasures, was above medium risk .\nThe risk assessment document should evaluate the risks associated with a heavy lift operation at each stage of the process and\nshould include a contingency plan to address unforeseen internal and external circumstances.\nEach hazard should include a description of the potential risks, the existing controls in place to mitigate those risks, an initial risk\nrating calculation, and an identification of any additional controls required to further reduce the risk.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":166,"source_page_end":166,"raw_source_text":"Was a specific risk assessment provided for the heavy lift vessel, and are all lifting operations formally risk assessed? (V)\nGuide to Inspection\nThe inspector should record a Finding if any task was initiated when the residual risk rating, after implementing all control\nmeasures, was above medium risk .\nThe risk assessment document should evaluate the risks associated with a heavy lift operation at each stage of the process and\nshould include a contingency plan to address unforeseen internal and external circumstances.\nEach hazard should include a description of the potential risks, the existing controls in place to mitigate those risks, an initial risk\nrating calculation, and an identification of any additional controls required to further reduce the risk.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.3","internal_question_no":"08F.003","question_sort_key":8600300.358,"question_text":"Does the heavy lift vessel have a competence and training matrix that addresses the planning and execution of lifting operations, as well as the maintenance and operation of lifting equipment and ballast control operations?","guide_to_inspection":"The inspector should verify that the crew is adequately trained and certified to conduct inspections of lifting equipment. The\ninspector should check that refresher training is conducted for specialised roles, such as\noffshore crane operators and ballast control operators.\nAll persons involved in planning/performing lifting operations and maintaining lifting equipment shall be trained and competent\nfor their role. Refresher training and periodic assessment is necessary to assure competence.\nThe Safety Management System should establish clear competency standards for all critical roles and set out a defined\nprocess to ensure that personnel involved in planning and executing lifting operations are suitably qualified and capable.\nThe inspector should check for the availability of a training matrix and confirm that the crew engaged in lifting operations,\nincluding crane and ballast operations, has received the requisite training. Additionally, it is essential to ensure that records of\ntraining and certifications are maintained on board.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":166,"source_page_end":166,"raw_source_text":"Does the heavy lift vessel have a competence and training matrix that addresses the planning and execution\nof lifting operations, as well as the maintenance and operation of lifting equipment and ballast control operations? (V)\nGuide to Inspection\nThe inspector should verify that the crew is adequately trained and certified to conduct inspections of lifting equipment. The\ninspector should check that refresher training is conducted for specialised roles, such as\noffshore crane operators and ballast control operators.\nAll persons involved in planning/performing lifting operations and maintaining lifting equipment shall be trained and competent\nfor their role. Refresher training and periodic assessment is necessary to assure competence.\nThe Safety Management System should establish clear competency standards for all critical roles and set out a defined\nprocess to ensure that personnel involved in planning and executing lifting operations are suitably qualified and capable.\nThe inspector should check for the availability of a training matrix and confirm that the crew engaged in lifting operations,\nincluding crane and ballast operations, has received the requisite training. Additionally, it is essential to ensure that records of\ntraining and certifications are maintained on board.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.4","internal_question_no":"08F.004","question_sort_key":8600400.359,"question_text":"Are there documented procedures in place by the vessel’s manager to ensure that the Master receives the necessary pre-voyage guidance?","guide_to_inspection":"The vessel manager’s procedure should include guidelines on various issues such as weather restrictions, voyage routing,\nmotion limitations, project-specific lift analysis, and the transport manual.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":166,"source_page_end":166,"raw_source_text":"Are there documented procedures in place by the vessel’s manager to ensure that the Master receives the\nnecessary pre-voyage guidance? (V)\nGuide to Inspection\nThe vessel manager’s procedure should include guidelines on various issues such as weather restrictions, voyage routing,\nmotion limitations, project-specific lift analysis, and the transport manual.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.5","internal_question_no":"08F.005","question_sort_key":8600500.36,"question_text":"Was the heavy lifting vessel equipped with an effective lifting equipment management system?","guide_to_inspection":"An effective lifting equipment management system should include the following key elements:\n> All equipment must be clearly marked to correspond with its certification.\n> Valid certificates for each item should be readily available on board.\n> Defined inspection and maintenance standards should apply to lifting equipment, including loose gear and associated\ncomponents.\n> Clear guidelines should be established for the safe retirement of wire ropes.\n> Robust controls should be in place to prevent unauthorised alterations to lifting equipment.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":166,"source_page_end":166,"raw_source_text":"Was the heavy lifting vessel equipped with an effective lifting equipment management system? (V)\nGuide to Inspection\nAn effective lifting equipment management system should include the following key elements:\n> All equipment must be clearly marked to correspond with its certification.\n> Valid certificates for each item should be readily available on board.\n> Defined inspection and maintenance standards should apply to lifting equipment, including loose gear and associated\ncomponents.\n> Clear guidelines should be established for the safe retirement of wire ropes.\n> Robust controls should be in place to prevent unauthorised alterations to lifting equipment.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.6","internal_question_no":"08F.006","question_sort_key":8600600.361,"question_text":"Does the heavy lift vessel have procedures in place that cover the general safety arrangements for activities conducted on the exposed working decks?","guide_to_inspection":"The procedure should include requirements for PPE, lifejackets, lifebuoys, safety signage, and the availability of fall arrestor\nequipment for multiple users in exposed areas.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Does the heavy lift vessel have procedures in place that cover the general safety arrangements for activities\nconducted on the exposed working decks? (V)\nGuide to Inspection\nThe procedure should include requirements for PPE, lifejackets, lifebuoys, safety signage, and the availability of fall arrestor\nequipment for multiple users in exposed areas.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.7","internal_question_no":"08F.007","question_sort_key":8600700.362,"question_text":"Do the emergency procedures address additional scenarios related to the vessel heavy lift operations, including loss of stability or watertight integrity, loss of moorings or station keeping, emergency disconnect, helicopter accidents, severe weather, tidal waves, tsunamis, and solitons?","guide_to_inspection":"Evidence should exist showing that personnel have been familiarised with scenarios related to emergencies associated with\nheavy lifting.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Do the emergency procedures address additional scenarios related to the vessel heavy lift operations, including\nloss of stability or watertight integrity, loss of moorings or station keeping, emergency disconnect, helicopter\naccidents, severe weather, tidal waves, tsunamis, and solitons? (V)\nGuide to Inspection\nEvidence should exist showing that personnel have been familiarised with scenarios related to emergencies associated with\nheavy lifting.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ101$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 10/15 imported.' AS result,
  '08D.010' AS chunk_first_question,
  '08F.007' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
